int dfs(Node* root) {
int sum = 0;
if
(!root->childrenDir.empty()) {
for (auto &p : root->childrenDir) {
sum += dfs(p.second);
}
}
//
计算当前文件
if
(!root->childrenFile.empty()) {
for (auto &p: root->childrenFile) {
sum += p.second->size;
}
}
//
更新当前目录总大小
root->size = sum;
return sum;
}
bool cmp(Node* &a, Node* &b) {
if (a->size ==
b->size) {
return a->name < b->name;
}
return a->size >
b->size;
}
